1	# SemanticVersionBumper.Tests.ps1
2	# Pester test suite for the semantic version bumper.
3	# TDD: these tests were written BEFORE the implementation.
4	# Run with: Invoke-Pester -Output Detailed
5	
6	BeforeAll {
7	    # Dot-source functions only (no main execution)
8	    . "$PSScriptRoot/Invoke-SemanticVersionBump.ps1" -LoadOnly
9	}
10	
11	Describe "Get-BumpType" {
12	    It "returns 'patch' for fix commits" {
13	        $commits = @("fix: correct typo", "chore: update deps")
14	        Get-BumpType -Commits $commits | Should -Be "patch"
15	    }
16	
17	    It "returns 'minor' for feat commits" {
18	        $commits = @("feat: add new feature", "fix: small fix")
19	        Get-BumpType -Commits $commits | Should -Be "minor"
20	    }
21	
22	    It "returns 'major' for BREAKING CHANGE commits" {
23	        $commits = @("feat: new api", "BREAKING CHANGE: removed old endpoint")
24	        Get-BumpType -Commits $commits | Should -Be "major"
25	    }
26	
27	    It "returns 'major' for ! (breaking) commits" {
28	        $commits = @("feat!: breaking feature change")
29	        Get-BumpType -Commits $commits | Should -Be "major"
30	    }
31	
32	    It "returns 'major' for fix! commits" {
33	        $commits = @("fix!: incompatible fix")
34	        Get-BumpType -Commits $commits | Should -Be "major"
35	    }
36	
37	    It "returns 'patch' when no conventional commits found" {
38	        $commits = @("update readme", "misc changes")
39	        Get-BumpType -Commits $commits | Should -Be "patch"
40	    }
41	
42	    It "prefers major over minor" {
43	        $commits = @("feat: new feature", "feat!: breaking change")
44	        Get-BumpType -Commits $commits | Should -Be "major"
45	    }
46	
47	    It "prefers minor over patch" {
48	        $commits = @("fix: small fix", "feat: new feature")
49	        Get-BumpType -Commits $commits | Should -Be "minor"
50	    }
51	}
52	
53	Describe "Invoke-BumpVersion" {
54	    It "bumps patch version" {
55	        Invoke-BumpVersion -Version "1.2.3" -BumpType "patch" | Should -Be "1.2.4"
56	    }
57	
58	    It "bumps minor version and resets patch" {
59	        Invoke-BumpVersion -Version "1.2.3" -BumpType "minor" | Should -Be "1.3.0"
60	    }
61	
62	    It "bumps major version and resets minor and patch" {
63	        Invoke-BumpVersion -Version "1.2.3" -BumpType "major" | Should -Be "2.0.0"
64	    }
65	
66	    It "handles patch on 1.0.0" {
67	        Invoke-BumpVersion -Version "1.0.0" -BumpType "patch" | Should -Be "1.0.1"
68	    }
69	
70	    It "handles minor on 1.0.0" {
71	        Invoke-BumpVersion -Version "1.0.0" -BumpType "minor" | Should -Be "1.1.0"
72	    }
73	
74	    It "handles major on 1.0.0" {
75	        Invoke-BumpVersion -Version "1.0.0" -BumpType "major" | Should -Be "2.0.0"
76	    }
77	
78	    It "handles large version numbers" {
79	        Invoke-BumpVersion -Version "10.20.30" -BumpType "patch" | Should -Be "10.20.31"
80	    }
81	}
82	
83	Describe "New-ChangelogEntry" {
84	    It "generates changelog with version header" {
85	        $entry = New-ChangelogEntry -Version "1.2.0" -Commits @("feat: add feature")
86	        $entry | Should -Match "## \[1\.2\.0\]"
87	    }
88	
89	    It "includes feat commits under Features section" {
90	        $entry = New-ChangelogEntry -Version "1.2.0" -Commits @("feat: add new feature")
91	        $entry | Should -Match "### Features"
92	        $entry | Should -Match "add new feature"
93	    }
94	
95	    It "includes fix commits under Bug Fixes section" {
96	        $entry = New-ChangelogEntry -Version "1.1.1" -Commits @("fix: correct bug")
97	        $entry | Should -Match "### Bug Fixes"
98	        $entry | Should -Match "correct bug"
99	    }
100	
101	    It "includes breaking changes section" {
102	        $entry = New-ChangelogEntry -Version "2.0.0" -Commits @("feat!: breaking API change")
103	        $entry | Should -Match "### Breaking Changes"
104	    }
105	
106	    It "includes date in changelog entry" {
107	        $entry = New-ChangelogEntry -Version "1.0.1" -Commits @("fix: a fix")
108	        $entry | Should -Match "\d{4}-\d{2}-\d{2}"
109	    }
110	
111	    It "handles multiple commit types" {
112	        $commits = @("feat: new feature", "fix: bug fix", "chore: cleanup")
113	        $entry = New-ChangelogEntry -Version "1.1.0" -Commits $commits
114	        $entry | Should -Match "### Features"
115	        $entry | Should -Match "### Bug Fixes"
116	    }
117	}
118	
119	Describe "Get-VersionFromFile" {
120	    It "reads version from version.json" {
121	        $tempFile = [System.IO.Path]::GetTempFileName()
122	        Set-Content -Path $tempFile -Value '{"version": "1.2.3"}'
123	        $version = Get-VersionFromFile -FilePath $tempFile
124	        $version | Should -Be "1.2.3"
125	        Remove-Item $tempFile
126	    }
127	
128	    It "reads version from package.json format" {
129	        $tempFile = [System.IO.Path]::GetTempFileName()
130	        Set-Content -Path $tempFile -Value '{"name": "myapp", "version": "2.0.1", "description": "test"}'
131	        $version = Get-VersionFromFile -FilePath $tempFile
132	        $version | Should -Be "2.0.1"
133	        Remove-Item $tempFile
134	    }
135	
136	    It "throws error for missing file" {
137	        { Get-VersionFromFile -FilePath "nonexistent-file-xyz.json" } | Should -Throw
138	    }
139	
140	    It "throws error when no version field" {
141	        $tempFile = [System.IO.Path]::GetTempFileName()
142	        Set-Content -Path $tempFile -Value '{"name": "myapp"}'
143	        { Get-VersionFromFile -FilePath $tempFile } | Should -Throw
144	        Remove-Item $tempFile
145	    }
146	}
147	
148	Describe "Set-VersionInFile" {
149	    It "updates version in version.json" {
150	        $tempFile = [System.IO.Path]::GetTempFileName()
151	        Set-Content -Path $tempFile -Value '{"version": "1.0.0"}'
152	        Set-VersionInFile -FilePath $tempFile -NewVersion "1.1.0"
153	        $content = Get-Content -Path $tempFile -Raw | ConvertFrom-Json
154	        $content.version | Should -Be "1.1.0"
155	        Remove-Item $tempFile
156	    }
157	
158	    It "preserves other fields when updating" {
159	        $tempFile = [System.IO.Path]::GetTempFileName()
160	        Set-Content -Path $tempFile -Value '{"name": "myapp", "version": "1.0.0", "author": "test"}'
161	        Set-VersionInFile -FilePath $tempFile -NewVersion "2.0.0"
162	        $content = Get-Content -Path $tempFile -Raw | ConvertFrom-Json
163	        $content.version | Should -Be "2.0.0"
164	        $content.name | Should -Be "myapp"
165	        $content.author | Should -Be "test"
166	        Remove-Item $tempFile
167	    }
168	}
169	
170	Describe "Invoke-SemanticVersionBump (integration)" {
171	    It "bumps minor for feat commit and updates file" {
172	        $tempDir = Join-Path ([System.IO.Path]::GetTempPath()) ([System.Guid]::NewGuid().ToString())
173	        New-Item -ItemType Directory -Path $tempDir | Out-Null
174	        $versionFile = Join-Path $tempDir "version.json"
175	        $commitsFile = Join-Path $tempDir "commits.txt"
176	        Set-Content -Path $versionFile -Value '{"version": "1.0.0"}'
177	        Set-Content -Path $commitsFile -Value "feat: add new feature`nfix: small fix"
178	
179	        $result = Invoke-SemanticVersionBump -VersionFilePath $versionFile -CommitsFilePath $commitsFile
180	
181	        $result.NewVersion | Should -Be "1.1.0"
182	        $result.BumpType | Should -Be "minor"
183	        $result.OldVersion | Should -Be "1.0.0"
184	        $result.Changelog | Should -Match "## \[1\.1\.0\]"
185	
186	        $updated = Get-Content -Path $versionFile -Raw | ConvertFrom-Json
187	        $updated.version | Should -Be "1.1.0"
188	
189	        Remove-Item -Recurse -Force $tempDir
190	    }
191	
192	    It "bumps patch for fix-only commits" {
193	        $tempDir = Join-Path ([System.IO.Path]::GetTempPath()) ([System.Guid]::NewGuid().ToString())
194	        New-Item -ItemType Directory -Path $tempDir | Out-Null
195	        $versionFile = Join-Path $tempDir "version.json"
196	        $commitsFile = Join-Path $tempDir "commits.txt"
197	        Set-Content -Path $versionFile -Value '{"version": "2.3.5"}'
198	        Set-Content -Path $commitsFile -Value "fix: correct null check`nfix: handle edge case"
199	
200	        $result = Invoke-SemanticVersionBump -VersionFilePath $versionFile -CommitsFilePath $commitsFile
201	
202	        $result.NewVersion | Should -Be "2.3.6"
203	        $result.BumpType | Should -Be "patch"
204	
205	        Remove-Item -Recurse -Force $tempDir
206	    }
